import { useEffect, useState } from "react"

function useCalculateSchedule(activePlan, totalAmount) {
    const [installment, setInstallment] = useState(0)
    const [date, setDate] = useState(new Date())
    const [plansSchedule, setPlanSchedule] = useState([])

    useEffect(() => {
        if (activePlan && totalAmount) {
            const { planDuration } = activePlan
            const calculatedInstallment = Number(totalAmount) / Number(planDuration)
            setInstallment(calculatedInstallment)
            const today = new Date(date)
            //const arr = new Array(Number(planDuration)).fill({ dueDate: today.getMonth(), dueAmt: calculatedInstallment })
            const arr = Array.from({ length: planDuration }, (_, i) => {
                return { dueDate: today.getMonth(), dueAmt: calculatedInstallment }
            })
            setPlanSchedule([...arr])
        }
    }, [activePlan, totalAmount])

    return plansSchedule

}

export default useCalculateSchedule
